// Service Interface
@WebService
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL)
interface XmlProcessorService {

    /**
     * Accepts an XML document as a string, parses it using DocumentBuilder,
     * and processes its content.
     *
     * @param xmlPayload The XML document as a string. This is expected to be the content
     *                   of the SOAP body, not the full SOAP envelope.
     * @return A string indicating the result of the processing, including
     *         extracted information or error messages.
     */
    @WebMethod
    String processXmlDocument(String xmlPayload);
}

// Service Implementation
@WebService(endpointInterface = "com.example.xmlprocessor.XmlProcessorService")
class XmlProcessorServiceImpl implements XmlProcessorService {

    private static final Logger LOGGER = Logger.getLogger(XmlProcessorServiceImpl.class.getName());

    @Override
    public String processXmlDocument(String xmlPayload) {
        LOGGER.info("Received XML payload:\n" + xmlPayload);
        
        try {
            // Configure DocumentBuilderFactory for security (prevent XXE attacks)
            // It's crucial for enterprise data integration platforms handling external XML.
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true); // Disallow DOCTYPE declarations
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false); // Disable external general entities
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false); // Disable external parameter entities
            dbf.setXIncludeAware(false); // Disable XInclude processing
            dbf.setExpandEntityReferences(false); // Prevent entity expansion (security measure)
            
            DocumentBuilder db = dbf.newDocumentBuilder();
            
            // Parse the XML string into a Document object using StringReader and InputSource.
            // This is how DocumentBuilder processes XML provided as a String.
            Document document = db.parse(new InputSource(new StringReader(xmlPayload)));
            
            // Normalize the document for consistent parsing (optional but good practice).
            // This removes empty text nodes and combines adjacent text nodes.
            document.getDocumentElement().normalize();
            
            // --- Begin XML Processing Logic ---
            // This section demonstrates how to navigate and extract data from
            // a complex XML structure with nested elements and attributes.
            StringBuilder processingResult = new StringBuilder();
            
            Element rootElement = document.getDocumentElement();
            processingResult.append("Root Element: ").append(rootElement.getNodeName()).append("\n");
            
            // Example: Extract OrderId from the root
            NodeList orderIdList = rootElement.getElementsByTagName("OrderId");
            if (orderIdList.getLength() > 0) {
                String orderId = orderIdList.item(0).getTextContent();
                processingResult.append("  OrderId: ").append(orderId).append("\n");
            }
            
            // Example: Extract Customer information, including attributes and nested elements
            NodeList customerList = rootElement.getElementsByTagName("Customer");
            for (int i = 0; i < customerList.getLength(); i++) {
                Node customerNode = customerList.item(i);
                if (customerNode.getNodeType() == Node.ELEMENT_NODE) {
                    Element customerElement = (Element) customerNode;
                    processingResult.append("  Customer ID: ").append(customerElement.getAttribute("id")).append("\n");
                    
                    NodeList nameList = customerElement.getElementsByTagName("Name");
                    if (nameList.getLength() > 0) {
                        processingResult.append("    Name: ").append(nameList.item(0).getTextContent()).append("\n");
                    }

                    NodeList addressList = customerElement.getElementsByTagName("Address");
                    for (int j = 0; j < addressList.getLength(); j++) {
                        Node addressNode = addressList.item(j);
                        if (addressNode.getNodeType() == Node.ELEMENT_NODE) {
                            Element addressElement = (Element) addressNode;
                            processingResult.append("    Address Type: ").append(addressElement.getAttribute("type")).append("\n");
                            NodeList streetList = addressElement.getElementsByTagName("Street");
                            if (streetList.getLength() > 0) {
                                processingResult.append("      Street: ").append(streetList.item(0).getTextContent()).append("\n");
                            }
                            NodeList cityList = addressElement.getElementsByTagName("City");
                            if (cityList.getLength() > 0) {
                                processingResult.append("      City: ").append(cityList.item(0).getTextContent()).append("\n");
                            }
                            NodeList zipList = addressElement.getElementsByTagName("Zip");
                            if (zipList.getLength() > 0) {
                                processingResult.append("      Zip: ").append(zipList.item(0).getTextContent()).append("\n");
                            }
                        }
                    }
                    NodeList contactList = customerElement.getElementsByTagName("Contact");
                    if (contactList.getLength() > 0) {
                        Element contactElement = (Element) contactList.item(0);
                        NodeList emailList = contactElement.getElementsByTagName("Email");
                        if (emailList.getLength() > 0) {
                            processingResult.append("    Email: ").append(emailList.item(0).getTextContent()).append("\n");
                        }
                        NodeList phoneList = contactElement.getElementsByTagName("Phone");
                        if (phoneList.getLength() > 0) {
                            processingResult.append("    Phone: ").append(phoneList.item(0).getTextContent()).append("\n");
                        }
                    }
                }
            }
            
            // Example: Process nested 'Items' and 'Item' elements, including attributes
            NodeList itemsContainerList = rootElement.getElementsByTagName("Items");
            if (itemsContainerList.getLength() > 0) {
                Element itemsElement = (Element) itemsContainerList.item(0);
                NodeList itemList = itemsElement.getElementsByTagName("Item");
                processingResult.append("  Items:\n");
                for (int i = 0; i < itemList.getLength(); i++) {
                    Node itemNode = itemList.item(i);
                    if (itemNode.getNodeType() == Node.ELEMENT_NODE) {
                        Element itemElement = (Element) itemNode;
                        processingResult.append("    Item SKU: ").append(itemElement.getAttribute("sku")).append("\n");
                        NodeList itemNameList = itemElement.getElementsByTagName("Name");
                        if (itemNameList.getLength() > 0) {
                            processingResult.append("      Name: ").append(itemNameList.item(0).getTextContent()).append("\n");
                        }
                        NodeList quantityList = itemElement.getElementsByTagName("Quantity");
                        if (quantityList.getLength() > 0) {
                            processingResult.append("      Quantity: ").append(quantityList.item(0).getTextContent()).append("\n");
                        }
                        NodeList priceList = itemElement.getElementsByTagName("Price");
                        if (priceList.getLength() > 0) {
                            processingResult.append("      Price: ").append(priceList.item(0).getTextContent()).append("\n");
                        }
                    }
                }
            }

            // Example: Extract TotalAmount
            NodeList totalAmountList = rootElement.getElementsByTagName("TotalAmount");
            if (totalAmountList.getLength() > 0) {
                String totalAmount = totalAmountList.item(0).getTextContent();
                processingResult.append("  Total Amount: ").append(totalAmount).append("\n");
            }

            // In a real application, you would typically transform this extracted data
            // into Java objects, validate it, persist it to a database, or
            // forward it to another system for further processing.
            // For large XML payloads, DOM parsing loads the entire document into memory.
            // For truly enormous payloads (multi-gigabyte), consider SAX or StAX for
            // stream-based parsing to avoid OutOfMemoryError. However, DocumentBuilder
            // (DOM) is suitable for many "large" enterprise XML documents up to
            // several hundreds of megabytes, depending on available memory.

            LOGGER.info("Successfully processed XML. Extracted data:\n" + processingResult.toString());
            return "XML Document Processed Successfully. Extracted:\n" + processingResult.toString();

        } catch (ParserConfigurationException e) {
            LOGGER.log(Level.SEVERE, "Error configuring XML parser: " + e.getMessage(), e);
            return "Error: XML Parser Configuration Failed - " + e.getMessage();
        } catch (SAXException e) {
            LOGGER.log(Level.SEVERE, "Error parsing XML document: " + e.getMessage(), e);
            return "Error: Invalid XML Document - " + e.getMessage();
        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "I/O error during XML parsing: " + e.getMessage(), e);
            return "Error: I/O Error during XML Parsing - " + e.getMessage();
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "An unexpected error occurred during XML processing: " + e.getMessage(), e);
            return "Error: An unexpected error occurred - " + e.getMessage();
        }
    }
}

